                                </div>
                                <DropdownMenu>
                                    <DropdownMenuTrigger asChild>
                                        <Button variant="ghost" size="icon" className="h-10 w-10 bg-white/[0.02] border border-white/5 rounded-xl hover:text-ch-orange">
                                            <MoreHorizontal className="w-5 h-5" />
                                        </Button>
                                    </DropdownMenuTrigger>
                                    <DropdownMenuContent align="end" className="bg-ch-black-soft border-white/10 w-48 font-black uppercase text-[10px] tracking-widest">
                                        <DropdownMenuItem onClick={() => handleEdit(policy)} className="py-3 cursor-pointer">
                                            <Edit2 className="w-4 h-4 mr-3 text-blue-400" /> Editar Regra
                                        </DropdownMenuItem>
                                        <DropdownMenuItem
                                            onClick={() => handleDelete(policy.id)}
