}

import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { Eye, EyeOff, Loader2 } from 'lucide-react';

export default function Register() {
    const [formData, setFormData] = useState({
        firstName: '',
        lastName: '',
        email: '',
        password: '',
        confirmPassword: '',
        companyName: '',
    });
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const { signUp } = useAuth();
    const navigate = useNavigate();
    const { toast } = useToast();

    const updateField = (field: string, value: string) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        const { firstName, lastName, email, password, confirmPassword, companyName } = formData;

        // Validation
        if (!email || !password || !firstName || !companyName) {
            toast({
                title: 'Campos obrigatórios',
                description: 'Por favor, preencha todos os campos obrigatórios.',
                variant: 'destructive',
            });
            return;
        }

        if (password.length < 6) {
            toast({
                title: 'Senha muito curta',
                description: 'A senha deve ter pelo menos 6 caracteres.',
                variant: 'destructive',
            });
            return;
        }

        if (password !== confirmPassword) {
            toast({
                title: 'Senhas não conferem',
                description: 'As senhas digitadas não são iguais.',
                variant: 'destructive',
            });
            return;
        }

        setLoading(true);
        const { error } = await signUp(email, password, {
            first_name: firstName,
            last_name: lastName,
            company_name: companyName,
        });
        setLoading(false);

        if (error) {
            toast({
                title: 'Erro ao criar conta',
                description: error.message,
                variant: 'destructive',
            });
        } else {
            toast({
                title: 'Conta criada!',
                description: 'Verifique seu email para confirmar sua conta.',
            });
            navigate('/login');
        }
    };

    return (
        <div className="space-y-6 w-full max-w-md mx-auto">
            {/* Logo */}
            <div className="text-center">
                <div className="flex justify-center mb-4">
                    <div className="w-12 h-12 bg-ch-orange rounded-xl flex items-center justify-center">
                        <span className="font-bold text-ch-black text-2xl">C</span>
                    </div>
                </div>
                <h1 className="text-2xl font-bold gradient-text">Click Auditor</h1>
                <p className="text-ch-text-muted mt-2">Crie sua conta para começar</p>
            </div>

            {/* Form */}
            <div className="glass rounded-xl p-6 space-y-4">
                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-2">
                            <Label htmlFor="firstName">Nome *</Label>
                            <Input
                                id="firstName"
                                placeholder="João"
                                value={formData.firstName}
                                onChange={(e) => updateField('firstName', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange"
                                disabled={loading}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="lastName">Sobrenome</Label>
                            <Input
                                id="lastName"
                                placeholder="Silva"
                                value={formData.lastName}
                                onChange={(e) => updateField('lastName', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange"
                                disabled={loading}
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="companyName">Nome da Empresa *</Label>
                        <Input
                            id="companyName"
                            placeholder="Minha Empresa"
                            value={formData.companyName}
                            onChange={(e) => updateField('companyName', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="email">Email *</Label>
                        <Input
                            id="email"
                            type="email"
                            placeholder="seu@email.com"
                            value={formData.email}
                            onChange={(e) => updateField('email', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="password">Senha *</Label>
                        <div className="relative">
                            <Input
                                id="password"
                                type={showPassword ? 'text' : 'password'}
                                placeholder="••••••••"
                                value={formData.password}
                                onChange={(e) => updateField('password', e.target.value)}
                                className="bg-ch-black border-white/10 focus:border-ch-orange pr-10"
                                disabled={loading}
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-ch-text-dimmed hover:text-ch-white transition-colors"
                            >
                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                            </button>
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="confirmPassword">Confirmar Senha *</Label>
                        <Input
                            id="confirmPassword"
                            type="password"
                            placeholder="••••••••"
                            value={formData.confirmPassword}
                            onChange={(e) => updateField('confirmPassword', e.target.value)}
                            className="bg-ch-black border-white/10 focus:border-ch-orange"
                            disabled={loading}
                        />
                    </div>

                    <Button
                        type="submit"
                        className="w-full bg-ch-orange hover:bg-ch-orange-hover text-ch-black font-semibold"
                        disabled={loading}
                    >
                        {loading ? (
                            <>
                                <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                Criando conta...
                            </>
                        ) : (
                            'Criar Conta'
                        )}
                    </Button>
                </form>

                <div className="text-center text-sm">
                    <span className="text-ch-text-muted">Já tem uma conta? </span>
                    <Link
                        to="/login"
                        className="text-ch-orange hover:text-ch-orange-hover font-medium transition-colors"
                    >
                        Fazer login
                    </Link>
                </div>
            </div>
        </div>
    );
}
